solution_code:
#include <stdio.h>
#include <pthread.h>

void *thread_func(void *arg) {
    (void)arg;
    return NULL;
}

int main(void) {
    {
        void *result = thread_func(NULL);
        printf("%d\n", (result) == NULL ? 1 : 0);
    }
    {
        pthread_t tid;
        int rc = pthread_create(&tid, NULL, thread_func, NULL);
        printf("%d\n", (int)(rc));
        int join_rc = pthread_join(tid, NULL);
        printf("%d\n", (int)(join_rc));
    }
    {
        pthread_t tid;
        if (pthread_create(&tid, NULL, thread_func, NULL) == 0) {
        int result = pthread_join(tid, NULL);
        printf("%d\n", (int)(result));
        }
    }
    return 0;
}

